  reflection_prompt,
  safety_note,
  is_sensitive,
  is_active
)
values
  ('i_want_to_do_something_meaningful_i_only_have_5_minutes_1_choose_today_s_one_value', 'Choose Today''s One Value', 'Pick one value you want today to show and write one small action that would prove it.', 'Reflect', 'North Star', 'Easy', 10, 'I only have 5 minutes', 'I want to do something meaningful', array['quick', 'easy', 'deep', 'reflection', 'purpose']::text[], 'Starter', 0, 'A value becomes useful when it points to a real action.', 'You choose one value and one proof action for today.', 'What value would make today feel worthwhile?', null, false, true),
  ('i_want_to_do_something_meaningful_i_only_have_5_minutes_2_repair_one_tiny_promise', 'Repair One Tiny Promise', 'Find one small promise, reply, or intention you left hanging and take the smallest next step on it.', 'Reflect', 'North Star', 'Easy', 10, 'I only have 5 minutes', 'I want to do something meaningful', array['quick', 'easy', 'deep', 'reflection', 'purpose']::text[], 'Starter', 0, 'Meaning often returns when your actions line up with your word.', 'You take one next step on a small unfinished promise.', 'What promise still mattered to you?', null, false, true),
  ('i_want_to_do_something_meaningful_i_only_have_5_minutes_3_write_a_five_line_truth', 'Write a Five-Line Truth', 'Write five honest lines about what matters right now, then underline the sentence that feels most true.', 'Reflect', 'North Star', 'Easy', 10, 'I only have 5 minutes', 'I want to do something meaningful', array['quick', 'easy', 'deep', 'reflection', 'purpose']::text[], 'Starter', 0, 'Meaning gets clearer when vague feelings become words.', 'You write five honest lines and underline one true sentence.', 'Which sentence felt most alive?', null, false, true),
  ('i_want_to_do_something_meaningful_i_have_10_15_minutes_1_block_one_value_proof_action', 'Block One Value-Proof Action', 'Choose one value for this week and block one 15-minute action on your calendar that would prove it in real life.', 'Reflect', 'North Star', 'Easy', 10, 'I have 10-15 minutes', 'I want to do something meaningful', array['short', 'doable', 'deep', 'reflection', 'purpose']::text[], 'Starter', 0, 'Values become easier to live when they have a time, place, and action attached.', 'One value-proof action is scheduled.', 'What value do you want your week to show?', null, false, true),
  ('i_want_to_do_something_meaningful_i_have_10_15_minutes_2_send_one_earned_appreciation', 'Send One Earned Appreciation', 'Message someone whose effort shaped you and tell them one specific way it mattered.', 'Reflect', 'North Star', 'Easy', 10, 'I have 10-15 minutes', 'I want to do something meaningful', array['short', 'doable', 'deep', 'reflection', 'purpose']::text[], 'Starter', 0, 'Meaning deepens when appreciation becomes specific and shared.', 'You send one specific appreciation message.', 'What did this person help make possible?', null, false, true),
  ('i_want_to_do_something_meaningful_i_have_10_15_minutes_3_choose_a_small_contribution', 'Choose a Small Contribution', 'Choose one small contribution you can make today: help, teach, donate, share, clean, support, or encourage, then start it.', 'Reflect', 'North Star', 'Easy', 10, 'I have 10-15 minutes', 'I want to do something meaningful', array['short', 'doable', 'deep', 'reflection', 'purpose']::text[], 'Starter', 0, 'Contribution turns private intention into real-world evidence.', 'One small contribution is chosen and started.', 'What kind of contribution feels honest, not performative?', null, false, true),
  ('i_want_to_do_something_meaningful_i_have_15_30_minutes_1_do_a_values_audit', 'Do a Values Audit', 'Look at yesterday or last week and mark three actions that matched your values and one action you want to adjust.', 'Reflect', 'North Star', 'Medium', 25, 'I have 15-30 minutes', 'I want to do something meaningful', array['doable', 'focus', 'meaningful', 'deep', 'reflection', 'purpose']::text[], 'Starter', 0, 'A quick audit helps you steer without shaming yourself.', 'Three aligned actions and one adjustment are written down.', 'What pattern do you want to continue?', null, false, true),
  ('i_want_to_do_something_meaningful_i_have_15_30_minutes_2_move_a_meaningful_project_forward', 'Move a Meaningful Project Forward', 'Spend 25 minutes on one project, relationship, skill, or responsibility that still matters six months from now.', 'Reflect', 'North Star', 'Medium', 25, 'I have 15-30 minutes', 'I want to do something meaningful', array['doable', 'focus', 'meaningful', 'deep', 'reflection', 'purpose']::text[], 'Starter', 0, 'Meaningful work often needs protected attention more than motivation.', 'You complete 25 minutes of progress on something that matters long term.', 'Why does this still matter six months from now?', null, false, true),
  ('i_want_to_do_something_meaningful_i_have_15_30_minutes_3_make_one_life_easier_for_someone', 'Make One Life Easier for Someone', 'Do one practical task that genuinely makes another person''s day easier: arrange, clean, share, prepare, fix, or follow up.', 'Reflect', 'North Star', 'Medium', 25, 'I have 15-30 minutes', 'I want to do something meaningful', array['doable', 'focus', 'meaningful', 'deep', 'reflection', 'purpose']::text[], 'Starter', 0, 'Meaning can be simple when it reduces someone else''s load.', 'One practical helpful action is completed.', 'Whose load became a little lighter?', null, false, true),
  ('i_want_to_do_something_meaningful_i_have_more_than_30_minutes_1_design_a_seven_day_proof', 'Design a Seven-Day Proof', 'Choose one value and design a seven-day proof: one small daily action, when it happens, and how you will track it.', 'Reflect', 'North Star', 'Hard', 50, 'I have more than 30 minutes', 'I want to do something meaningful', array['deep', 'purpose', 'reflection']::text[], 'Starter', 0, 'A week of small proof turns meaning into lived behavior.', 'A seven-day value proof is written and scheduled.', 'What value deserves a week of evidence?', null, false, true),
  ('i_want_to_do_something_meaningful_i_have_more_than_30_minutes_2_finish_a_meaningful_loose_end', 'Finish a Meaningful Loose End', 'Pick one unfinished meaningful task and give it a full 45-minute block: letter, application, repair, plan, form, or project step.', 'Reflect', 'North Star', 'Hard', 50, 'I have more than 30 minutes', 'I want to do something meaningful', array['deep', 'purpose', 'reflection']::text[], 'Starter', 0, 'Loose ends that matter can quietly weigh on your identity.', 'One meaningful loose end has visible progress or closure.', 'What did finishing or moving this forward restore?', null, false, true),
  ('i_want_to_do_something_meaningful_i_have_more_than_30_minutes_3_create_a_personal_north_star_page', 'Create a Personal North Star Page', 'Write one page with what matters now, what you are no longer available for, and one action for the next 24 hours.', 'Reflect', 'North Star', 'Hard', 50, 'I have more than 30 minutes', 'I want to do something meaningful', array['deep', 'purpose', 'reflection']::text[], 'Starter', 0, 'A clear page can become a compass when everything feels equally loud.', 'One North Star page is written with a next action.', 'What are you ready to stop pretending is neutral?', null, false, true),
  ('i_want_a_small_courage_boost_i_only_have_5_minutes_1_ask_one_clear_question', 'Ask One Clear Question', 'Ask one question you have been avoiding because you did not want to look awkward, needy, or behind.', 'Connect', 'Tiny Dares', 'Easy', 10, 'I only have 5 minutes', 'I want a small courage boost', array['quick', 'easy', 'brave', 'confidence', 'discomfort']::text[], 'Starter', 0, 'Small courage grows when you let yourself need clarity.', 'You ask one clear question.', 'What made this question feel harder than it was?', 'Only do this if it feels safe and appropriate. A smaller version counts.', true, true),
  ('i_want_a_small_courage_boost_i_only_have_5_minutes_2_make_one_small_request', 'Make One Small Request', 'Ask for one small thing directly: a time, answer, favor, edit, introduction, price, or clarification.', 'Connect', 'Tiny Dares', 'Easy', 10, 'I only have 5 minutes', 'I want a small courage boost', array['quick', 'easy', 'brave', 'confidence', 'discomfort']::text[], 'Starter', 0, 'Direct requests train confidence without requiring a dramatic leap.', 'You make one clear, respectful request.', 'What did you learn by asking directly?', 'Only do this if it feels safe and appropriate. A smaller version counts.', true, true),
  ('i_want_a_small_courage_boost_i_only_have_5_minutes_3_use_your_real_voice', 'Use Your Real Voice', 'Send one voice note or say one sentence out loud that you would normally over-edit in text.', 'Connect', 'Tiny Dares', 'Easy', 10, 'I only have 5 minutes', 'I want a small courage boost', array['quick', 'easy', 'brave', 'confidence', 'discomfort']::text[], 'Starter', 0, 'Courage can be as small as letting your real voice take up space.', 'You send or speak one honest sentence.', 'What did your voice carry that text would hide?', null, false, true),
  ('i_want_a_small_courage_boost_i_have_10_15_minutes_1_ask_for_useful_feedback', 'Ask for Useful Feedback', 'Send one piece of work, idea, or plan to a safe person and ask one specific feedback question.', 'Connect', 'Tiny Dares', 'Easy', 10, 'I have 10-15 minutes', 'I want a small courage boost', array['short', 'doable', 'brave', 'confidence', 'discomfort']::text[], 'Starter', 0, 'Specific feedback makes improvement less scary than vague judgment.', 'You ask one safe person for one specific piece of feedback.', 'What feedback question felt most useful?', null, false, true),
  ('i_want_a_small_courage_boost_i_have_10_15_minutes_2_send_the_simple_invite', 'Send the Simple Invite', 'Invite someone to a walk, coffee, call, co-working block, or casual plan without overexplaining.', 'Connect', 'Tiny Dares', 'Easy', 10, 'I have 10-15 minutes', 'I want a small courage boost', array['short', 'doable', 'brave', 'confidence', 'discomfort']::text[], 'Starter', 0, 'Connection often needs one brave sentence, not a perfect plan.', 'You send one simple invitation.', 'What did you want to control before sending it?', null, false, true),
  ('i_want_a_small_courage_boost_i_have_10_15_minutes_3_move_one_draft_forward', 'Move One Draft Forward', 'Take one private draft and move it to the next step: outline, edit, send, upload, schedule, or request review.', 'Connect', 'Tiny Dares', 'Easy', 10, 'I have 10-15 minutes', 'I want a small courage boost', array['short', 'doable', 'brave', 'confidence', 'discomfort']::text[], 'Starter', 0, 'A draft becomes less scary when it moves one step forward.', 'One draft moves to a real next step.', 'What did this draft need more than perfection?', null, false, true),
  ('i_want_a_small_courage_boost_i_have_15_30_minutes_1_make_the_avoided_call', 'Make the Avoided Call', 'Make one practical call or send one serious message you have been delaying: appointment, repair, bill, booking, or follow-up.', 'Connect', 'Tiny Dares', 'Medium', 25, 'I have 15-30 minutes', 'I want a small courage boost', array['doable', 'focus', 'meaningful', 'brave', 'confidence', 'discomfort']::text[], 'Starter', 0, 'Avoided practical conversations grow heavier the longer they wait.', 'One delayed call or serious message is completed.', 'What did you expect to happen, and what actually happened?', null, false, true),
  ('i_want_a_small_courage_boost_i_have_15_30_minutes_2_publish_a_small_opinion', 'Publish a Small Opinion', 'Share one honest, respectful opinion, recommendation, or lesson in a post, message, review, meeting, or group.', 'Connect', 'Tiny Dares', 'Medium', 25, 'I have 15-30 minutes', 'I want a small courage boost', array['doable', 'focus', 'meaningful', 'brave', 'confidence', 'discomfort']::text[], 'Starter', 0, 'Courage grows when your point of view becomes visible in a low-stakes way.', 'You share one honest opinion or lesson where someone can see it.', 'What part of being visible felt uncomfortable?', null, false, true),
  ('i_want_a_small_courage_boost_i_have_15_30_minutes_3_apply_to_one_opportunity', 'Apply to One Opportunity', 'Apply, submit interest, or send a first message for one opportunity that is slightly outside your comfort zone.', 'Connect', 'Tiny Dares', 'Medium', 25, 'I have 15-30 minutes', 'I want a small courage boost', array['doable', 'focus', 'meaningful', 'brave', 'confidence', 'discomfort']::text[], 'Starter', 0, 'Trying creates more possibility than waiting until you feel fully ready.', 'One application, interest form, or first message is sent.', 'What story did you have to ignore to apply?', null, false, true),
  ('i_want_a_small_courage_boost_i_have_more_than_30_minutes_1_attend_the_first_session', 'Attend the First Session', 'Attend or register for one class, event, group, workshop, or session you have been curious about.', 'Connect', 'Tiny Dares', 'Hard', 50, 'I have more than 30 minutes', 'I want a small courage boost', array['deep', 'purpose', 'brave', 'confidence', 'discomfort']::text[], 'Starter', 0, 'Showing up once is often the hardest courage rep.', 'You attend, register, or put the first session on your calendar.', 'What part of showing up felt like a stretch?', null, false, true),
  ('i_want_a_small_courage_boost_i_have_more_than_30_minutes_2_prepare_the_hard_conversation', 'Prepare the Hard Conversation', 'Write the point of one hard conversation, what you need to say, and one calm opening sentence.', 'Connect', 'Tiny Dares', 'Hard', 50, 'I have more than 30 minutes', 'I want a small courage boost', array['deep', 'purpose', 'brave', 'confidence', 'discomfort']::text[], 'Starter', 0, 'Preparation lowers the chance that courage turns into panic or avoidance.', 'You write a calm opening and the main point you need to say.', 'What do you want to be honest about without being harsh?', 'Only do this if it feels safe and appropriate. A smaller version counts.', true, true),
  ('i_want_a_small_courage_boost_i_have_more_than_30_minutes_3_pitch_one_real_thing', 'Pitch One Real Thing', 'Create and send a simple pitch for one real thing: service, collaboration, project, idea, sale, or request for help.', 'Connect', 'Tiny Dares', 'Hard', 50, 'I have more than 30 minutes', 'I want a small courage boost', array['deep', 'purpose', 'brave', 'confidence', 'discomfort']::text[], 'Starter', 0, 'A pitch turns hidden ambition into a real-world attempt.', 'One simple pitch is written and sent or scheduled.', 'What are you asking the world to take seriously?', null, false, true)

