values
  ('i_want_to_do_something_kind_i_only_have_5_minutes_1_send_a_specific_thank_you', 'Send a Specific Thank-You', 'Send one message thanking someone for a specific effort, favor, lesson, introduction, or moment they may not know mattered.', 'Connect', 'Good Sparks', 'Easy', 10, 'I only have 5 minutes', 'I want to do something kind', array['quick', 'easy', 'kindness', 'gratitude', 'helpful']::text[], 'Starter', 0, 'Specific gratitude makes invisible effort feel seen.', 'You send one sincere, specific thank-you message.', 'What effort did you notice that might have gone unseen?', null, false, true),
  ('i_want_to_do_something_kind_i_only_have_5_minutes_2_compliment_the_effort', 'Compliment the Effort', 'Give one person a genuine compliment about their effort, care, consistency, or courage, not their looks or status.', 'Connect', 'Good Sparks', 'Easy', 10, 'I only have 5 minutes', 'I want to do something kind', array['quick', 'easy', 'kindness', 'gratitude', 'helpful']::text[], 'Starter', 0, 'People are often praised for outcomes, but effort is what they live through.', 'You give one effort-based compliment.', 'What effort became visible once you looked for it?', null, false, true),
  ('i_want_to_do_something_kind_i_only_have_5_minutes_3_leave_one_encouraging_comment', 'Leave One Encouraging Comment', 'Leave a thoughtful comment on someone''s work, post, project, business, art, or achievement.', 'Connect', 'Good Sparks', 'Easy', 10, 'I only have 5 minutes', 'I want to do something kind', array['quick', 'easy', 'kindness', 'gratitude', 'helpful']::text[], 'Starter', 0, 'Most people consume silently. Specific encouragement can become fuel.', 'You leave one specific encouraging comment.', 'What did you genuinely appreciate?', null, false, true),
  ('i_want_to_do_something_kind_i_have_10_15_minutes_1_write_a_helpful_review', 'Write a Helpful Review', 'Write a specific positive review for a local place, creator, freelancer, teacher, app, or service you genuinely value.', 'Connect', 'Good Sparks', 'Easy', 10, 'I have 10-15 minutes', 'I want to do something kind', array['short', 'doable', 'kindness', 'gratitude', 'helpful']::text[], 'Starter', 0, 'A thoughtful review can help someone earn trust beyond your private appreciation.', 'One specific helpful review is posted or drafted.', 'What deserved public credit?', null, false, true),
  ('i_want_to_do_something_kind_i_have_10_15_minutes_2_remove_one_tiny_burden', 'Remove One Tiny Burden', 'Do one small task that reduces someone else''s load: wash, refill, arrange, pick up, share, remind, or handle something.', 'Connect', 'Good Sparks', 'Easy', 10, 'I have 10-15 minutes', 'I want to do something kind', array['short', 'doable', 'kindness', 'gratitude', 'helpful']::text[], 'Starter', 0, 'Kindness becomes real when it removes friction from someone''s day.', 'One tiny burden is removed for someone else.', 'Whose day did you make slightly easier?', null, false, true),
  ('i_want_to_do_something_kind_i_have_10_15_minutes_3_make_a_warm_introduction', 'Make a Warm Introduction', 'Introduce two people who could genuinely help, encourage, or interest each other, with one sentence of context for each.', 'Connect', 'Good Sparks', 'Easy', 10, 'I have 10-15 minutes', 'I want to do something kind', array['short', 'doable', 'kindness', 'gratitude', 'helpful']::text[], 'Starter', 0, 'Good introductions create possibilities that would not happen alone.', 'One thoughtful introduction is sent.', 'Why might these two people benefit from knowing each other?', null, false, true),
  ('i_want_to_do_something_kind_i_have_15_30_minutes_1_write_a_real_recommendation', 'Write a Real Recommendation', 'Write a short recommendation, testimonial, reference note, or endorsement for someone whose work you trust.', 'Connect', 'Good Sparks', 'Medium', 25, 'I have 15-30 minutes', 'I want to do something kind', array['doable', 'focus', 'meaningful', 'kindness', 'gratitude', 'helpful']::text[], 'Starter', 0, 'Specific public support can open doors for people quietly doing good work.', 'One recommendation, testimonial, or endorsement is written and sent or posted.', 'What strength of theirs deserves to be named?', null, false, true),
  ('i_want_to_do_something_kind_i_have_15_30_minutes_2_help_with_one_practical_thing', 'Help With One Practical Thing', 'Ask someone nearby what would help today, then complete one practical helpful action within your capacity.', 'Connect', 'Good Sparks', 'Medium', 25, 'I have 15-30 minutes', 'I want to do something kind', array['doable', 'focus', 'meaningful', 'kindness', 'gratitude', 'helpful']::text[], 'Starter', 0, 'Kindness lands better when it answers a real need instead of guessing.', 'You ask and complete one practical helpful action.', 'What did they actually need?', null, false, true),
  ('i_want_to_do_something_kind_i_have_15_30_minutes_3_make_a_small_care_delivery', 'Make a Small Care Delivery', 'Prepare or send one small care item: snack, note, resource, link, errand, playlist, or useful information.', 'Connect', 'Good Sparks', 'Medium', 25, 'I have 15-30 minutes', 'I want to do something kind', array['doable', 'focus', 'meaningful', 'kindness', 'gratitude', 'helpful']::text[], 'Starter', 0, 'Small care becomes memorable when it arrives without being demanded.', 'One small care item is prepared, sent, or delivered.', 'What made this care feel personal?', null, false, true),
  ('i_want_to_do_something_kind_i_have_more_than_30_minutes_1_do_a_local_help_block', 'Do a Local Help Block', 'Spend 45 minutes helping a person, neighbor, local group, creator, or small business with a concrete task.', 'Connect', 'Good Sparks', 'Hard', 50, 'I have more than 30 minutes', 'I want to do something kind', array['deep', 'purpose', 'kindness', 'gratitude', 'helpful']::text[], 'Starter', 0, 'Longer kindness blocks create real help, not just a nice intention.', 'One 45-minute concrete help block is completed.', 'What became easier because you showed up?', null, false, true),
  ('i_want_to_do_something_kind_i_have_more_than_30_minutes_2_cook_or_prepare_something_to_share', 'Cook or Prepare Something to Share', 'Make or prepare something simple to share: tea, snack, meal, notes, resource list, playlist, or care kit.', 'Connect', 'Good Sparks', 'Hard', 50, 'I have more than 30 minutes', 'I want to do something kind', array['deep', 'purpose', 'kindness', 'gratitude', 'helpful']::text[], 'Starter', 0, 'Shared effort can make ordinary care feel tangible.', 'One shareable thing is prepared and offered.', 'What felt generous but still realistic?', null, false, true),
  ('i_want_to_do_something_kind_i_have_more_than_30_minutes_3_organize_a_kindness_chain', 'Organize a Kindness Chain', 'Start one small kindness chain by inviting two people to thank, support, review, or help someone specific.', 'Connect', 'Good Sparks', 'Hard', 50, 'I have more than 30 minutes', 'I want to do something kind', array['deep', 'purpose', 'kindness', 'gratitude', 'helpful']::text[], 'Starter', 0, 'Kindness can multiply when the next step is clear and small.', 'Two people are invited into one clear kindness action.', 'Who could use more visible support right now?', null, false, true),
  ('i_want_to_feel_more_present_i_only_have_5_minutes_1_step_outside_and_notice_five_things', 'Step Outside and Notice Five Things', 'Step outside or near a window and name five things you can see, hear, feel, smell, or notice.', 'Reset', 'Fresh Trails', 'Easy', 10, 'I only have 5 minutes', 'I want to feel more present', array['quick', 'easy', 'offline', 'nature', 'movement']::text[], 'Starter', 0, 'Presence often returns through the senses before it returns through thoughts.', 'You notice five real-world details.', 'Which detail pulled you into the present?', null, false, true),
  ('i_want_to_feel_more_present_i_only_have_5_minutes_2_observe_one_object_slowly', 'Observe One Object Slowly', 'Pick one ordinary object and study it for two minutes, then describe five details you usually miss.', 'Reset', 'Fresh Trails', 'Easy', 10, 'I only have 5 minutes', 'I want to feel more present', array['quick', 'easy', 'offline', 'nature', 'movement']::text[], 'Starter', 0, 'Slowing attention turns ordinary reality back into something noticeable.', 'You describe five details about one object.', 'What had you never noticed before?', null, false, true),
  ('i_want_to_feel_more_present_i_only_have_5_minutes_3_do_a_no_scroll_transition', 'Do a No-Scroll Transition', 'Before switching tasks, spend five minutes doing nothing with your phone away: stand, breathe, sip, or look around.', 'Reset', 'Fresh Trails', 'Easy', 10, 'I only have 5 minutes', 'I want to feel more present', array['quick', 'easy', 'offline', 'nature', 'movement']::text[], 'Starter', 0, 'Transitions get swallowed by screens. A pause gives your day edges again.', 'You complete one five-minute no-scroll transition.', 'What did the pause reveal?', null, false, true),
  ('i_want_to_feel_more_present_i_have_10_15_minutes_1_take_a_fresh_route', 'Take a Fresh Route', 'On a walk or errand, take one safe route you do not usually take and notice three details you would normally miss.', 'Reset', 'Fresh Trails', 'Easy', 10, 'I have 10-15 minutes', 'I want to feel more present', array['short', 'doable', 'offline', 'nature', 'movement']::text[], 'Starter', 0, 'A small route change interrupts autopilot without needing a big adventure.', 'You take a safe fresh route and notice three real-world details.', 'What detail made the route feel different?', null, false, true),
  ('i_want_to_feel_more_present_i_have_10_15_minutes_2_do_one_chore_fully_present', 'Do One Chore Fully Present', 'Choose one ordinary chore and do it without audio, scrolling, or multitasking, paying attention to the physical steps.', 'Reset', 'Fresh Trails', 'Easy', 10, 'I have 10-15 minutes', 'I want to feel more present', array['short', 'doable', 'offline', 'nature', 'movement']::text[], 'Starter', 0, 'A chore can become a reset when it is not treated like background noise.', 'One small chore is completed without digital input.', 'What did the task feel like when it had your full attention?', null, false, true),
  ('i_want_to_feel_more_present_i_have_10_15_minutes_3_make_a_three_photo_reality_check', 'Make a Three-Photo Reality Check', 'Take three photos of real-life details around you that capture today''s texture, not your face or a performance.', 'Reset', 'Fresh Trails', 'Easy', 10, 'I have 10-15 minutes', 'I want to feel more present', array['short', 'doable', 'offline', 'nature', 'movement']::text[], 'Starter', 0, 'Noticing real details can pull you out of abstract mental loops.', 'You capture three real-world details.', 'Which photo best represents today?', null, false, true),
  ('i_want_to_feel_more_present_i_have_15_30_minutes_1_sit_somewhere_without_performing', 'Sit Somewhere Without Performing', 'Sit in a public or outdoor place for 20 minutes without posting, scrolling, shopping, or optimizing anything.', 'Reset', 'Fresh Trails', 'Medium', 25, 'I have 15-30 minutes', 'I want to feel more present', array['doable', 'focus', 'meaningful', 'offline', 'nature', 'movement']::text[], 'Starter', 0, 'Presence deepens when you are allowed to simply be in a place.', 'You sit for 20 minutes without turning it into content or productivity.', 'What did you notice once you stopped performing?', null, false, true),
  ('i_want_to_feel_more_present_i_have_15_30_minutes_2_do_a_sensory_walk', 'Do a Sensory Walk', 'Walk for 20 minutes and intentionally notice five colors, five sounds, five textures, and one thing changing.', 'Reset', 'Fresh Trails', 'Medium', 25, 'I have 15-30 minutes', 'I want to feel more present', array['doable', 'focus', 'meaningful', 'offline', 'nature', 'movement']::text[], 'Starter', 0, 'A sensory walk gives attention a job that is rooted in the real world.', 'You complete the walk and notice the sensory list.', 'Which sense felt most awake?', null, false, true),
  ('i_want_to_feel_more_present_i_have_15_30_minutes_3_have_a_phone_free_meal', 'Have a Phone-Free Meal', 'Eat one meal or snack without your phone, laptop, TV, or reading, even if it is simple.', 'Reset', 'Fresh Trails', 'Medium', 25, 'I have 15-30 minutes', 'I want to feel more present', array['doable', 'focus', 'meaningful', 'offline', 'nature', 'movement']::text[], 'Starter', 0, 'Eating without input can make your body feel less like an afterthought.', 'One meal or snack is eaten without digital input.', 'What changed when eating was the only activity?', null, false, true),
  ('i_want_to_feel_more_present_i_have_more_than_30_minutes_1_do_an_offline_morning_block', 'Do an Offline Morning Block', 'Spend the first 45 minutes after waking without social apps, news, or scrolling, and choose one grounded action instead.', 'Reset', 'Fresh Trails', 'Hard', 50, 'I have more than 30 minutes', 'I want to feel more present', array['deep', 'purpose', 'offline', 'nature', 'movement']::text[], 'Starter', 0, 'How you enter the day can decide whether your attention belongs to you.', 'One offline morning block is completed or scheduled for tomorrow.', 'What did your attention want before the world entered?', null, false, true),
  ('i_want_to_feel_more_present_i_have_more_than_30_minutes_2_explore_one_nearby_place', 'Explore One Nearby Place', 'Visit a nearby park, street, library, market, temple, cafe, or public place and notice what makes it specific.', 'Reset', 'Fresh Trails', 'Hard', 50, 'I have more than 30 minutes', 'I want to feel more present', array['deep', 'purpose', 'offline', 'nature', 'movement']::text[], 'Starter', 0, 'Exploration reminds your brain that life is larger than your usual loop.', 'You visit one nearby place and record three specific observations.', 'What made this place feel alive?', null, false, true),
  ('i_want_to_feel_more_present_i_have_more_than_30_minutes_3_take_a_long_audio_free_walk', 'Take a Long Audio-Free Walk', 'Walk for 40 minutes without music, podcasts, calls, or scrolling, and let your mind settle into the surroundings.', 'Reset', 'Fresh Trails', 'Hard', 50, 'I have more than 30 minutes', 'I want to feel more present', array['deep', 'purpose', 'offline', 'nature', 'movement']::text[], 'Starter', 0, 'A long no-input walk can make the world feel real again.', 'You complete a 40-minute audio-free walk.', 'What appeared once nothing was filling the silence?', null, false, true)

